const cfg = $('Konfiguration').first().json;
const docs = $json.results || [];

function tagIds(tags) {
  return (tags || [])
    .map(t => {
      if (typeof t === 'number') return t;
      if (typeof t === 'string') return Number(t);
      if (typeof t === 'object' && t !== null) return Number(t.id ?? t.pk);
      return null;
    })
    .filter(Boolean);
}

const filtered = docs.filter(doc => {
  const tags = tagIds(doc.tags);

  // NICHT verarbeiten, wenn bereits bezahlt
  if (tags.includes(Number(cfg.paperless_paid_tag_id))) {
    return false;
  }

  // Verarbeiten, wenn Rechnung und Zahlung unsicher
  if (tags.includes(Number(cfg.paperless_unsure_tag_id))) {
    return true;
  }

  // Optional: auch noch offene Zahlungen verarbeiten
  if (tags.includes(Number(cfg.paperless_open_tag_id))) {
    return true;
  }

  // Neue Rechnungen ohne Bezahlt-Tag auch verarbeiten
  return true;
});

return filtered.map(doc => ({ json: doc }));

const doc = $json;

return [{
  json: {
    paperless_id: doc.id,
    paperless_title: doc.title || '',
    original_filename: doc.original_filename || '',
    created: doc.created || null,
    added: doc.added || null,
    content: doc.content || '',
    existing_tags: doc.tags || [],
    correspondent: doc.correspondent || null,
    document_type: doc.document_type || null
  }
}];

const base = $('Rechnungstext vorbereiten').first().json;

let raw =
  $json.output?.[0]?.content?.[0]?.text ||
  $json.output_text ||
  $json.output ||
  $json.text ||
  $json.message?.content ||
  $json.choices?.[0]?.message?.content ||
  '{}';

// Falls output ein Array/Objekt ist
if (Array.isArray(raw)) {
  raw = raw?.[0]?.content?.[0]?.text || JSON.stringify(raw);
}

if (typeof raw !== 'string') {
  raw = JSON.stringify(raw);
}

raw = raw
  .replace(/```json/g, '')
  .replace(/```/g, '')
  .trim();

let parsed;

try {
  parsed = JSON.parse(raw);
} catch (e) {
  parsed = {
    is_invoice: false,
    creditor_name: null,
    invoice_number: null,
    customer_number: null,
    amount_total: null,
    currency: "EUR",
    due_date: null,
    invoice_date: null,
    iban: null,
    bic: null,
    payment_reference: null,
    suggested_firefly_search_terms: [],
    confidence: 0,
    reason: "ChatGPT-Antwort konnte nicht als JSON gelesen werden. Raw: " + raw.slice(0, 500)
  };
}

parsed.paperless_id = base.paperless_id;
parsed.paperless_title = base.paperless_title;
parsed.original_filename = base.original_filename;
parsed.existing_tags = base.existing_tags || [];

return [
  {
    json: parsed
  }
];

const invoice = $json;

const terms = [];

// Sehr gute Suchbegriffe einzeln sammeln
if (invoice.creditor_name) terms.push(invoice.creditor_name);
if (invoice.invoice_number) terms.push(invoice.invoice_number);
if (invoice.customer_number) terms.push(invoice.customer_number);
if (invoice.iban) terms.push(invoice.iban);
if (invoice.bic) terms.push(invoice.bic);
if (invoice.payment_reference) terms.push(invoice.payment_reference);

if (Array.isArray(invoice.suggested_firefly_search_terms)) {
  terms.push(...invoice.suggested_firefly_search_terms);
}

// Begriffe bereinigen
const clean = [...new Set(
  terms
    .filter(Boolean)
    .map(t => String(t).trim())
    .filter(t => t.length >= 3)
)];

// Smarte Firefly-Suchen bauen
const queries = [];

// 1. Rechnungsnummer einzeln
if (invoice.invoice_number) queries.push(String(invoice.invoice_number));

// 2. Verwendungszweck einzeln
if (invoice.payment_reference) queries.push(String(invoice.payment_reference));

// 3. IBAN einzeln
if (invoice.iban) queries.push(String(invoice.iban).replace(/\s+/g, ''));

// 4. Empfänger gekürzt
if (invoice.creditor_name) {
  const shortCreditor = String(invoice.creditor_name)
    .replace(/GmbH|Co\. KG|KG|UG|AG|Ltd|&/gi, '')
    .replace(/\s+/g, ' ')
    .trim();

  queries.push(shortCreditor);
}

// 5. Suggested Terms einzeln
for (const t of clean) {
  queries.push(t);
}

// 6. Kombi: Empfänger + Rechnungsnummer
if (invoice.creditor_name && invoice.invoice_number) {
  queries.push(`${invoice.creditor_name} ${invoice.invoice_number}`);
}

// 7. Kombi: Empfänger + Verwendungszweck
if (invoice.creditor_name && invoice.payment_reference) {
  queries.push(`${invoice.creditor_name} ${invoice.payment_reference}`);
}

// Duplikate entfernen, max. 8 Suchläufe
const finalQueries = [...new Set(
  queries
    .map(q => String(q).trim())
    .filter(q => q.length >= 3)
)].slice(0, 8);

// Wenn gar nichts da ist, mindestens Titel nutzen
if (finalQueries.length === 0 && invoice.paperless_title) {
  finalQueries.push(invoice.paperless_title);
}

// Aus 1 Rechnung mehrere Items machen
return finalQueries.map(query => ({
  json: {
    ...invoice,
    firefly_query: query
  }
}));

// Original-Rechnung aus dem ersten Suchparameter-Item
const invoice = $('Firefly Suchparameter bauen').first().json;

// Alle Firefly-Node-Items lesen
const items = $input.all();

const allCandidates = [];

for (const item of items) {
  let fireflyRaw = item.json;

  // Bei dir kommt data teilweise als JSON-String
  if (typeof item.json.data === 'string') {
    try {
      fireflyRaw = JSON.parse(item.json.data);
    } catch (e) {
      fireflyRaw = {
        data: [],
        parse_error: e.message,
        raw: item.json.data
      };
    }
  }

  const transactionsRaw = Array.isArray(fireflyRaw.data)
    ? fireflyRaw.data
    : [];

  for (const txItem of transactionsRaw) {
    const attr = txItem.attributes || {};
    const txs = attr.transactions || [];

    for (const tx of txs) {
      allCandidates.push({
        transaction_id: txItem.id,
        date: tx.date || null,
        description: tx.description || '',
        amount: tx.amount || null,
        currency: tx.currency_code || tx.currency_symbol || null,
        source_name: tx.source_name || '',
        destination_name: tx.destination_name || '',
        category_name: tx.category_name || '',
        notes: tx.notes || '',
        tags: tx.tags || [],
        search_query_used: item.json.firefly_query || invoice.firefly_query || ''
      });
    }
  }
}

// Duplikate anhand transaction_id + amount + date entfernen
const seen = new Set();
const candidates = allCandidates.filter(c => {
  const key = `${c.transaction_id}|${c.date}|${c.amount}|${c.description}`;
  if (seen.has(key)) return false;
  seen.add(key);
  return true;
});

return [
  {
    json: {
      invoice,
      candidates,
      firefly_result_count: candidates.length,
      firefly_searches_used: items.map(i => i.json.firefly_query).filter(Boolean)
    }
  }
];

// ChatGPT-Text holen
const raw = $json.output?.[0]?.content?.[0]?.text;

if (!raw) {
  throw new Error('Kein ChatGPT output[0].content[0].text gefunden');
}

// JSON aus ChatGPT parsen
let parsed;
try {
  parsed = JSON.parse(raw);
} catch (error) {
  throw new Error('ChatGPT-Antwort ist kein gültiges JSON: ' + raw);
}

// Status normalisieren
const status = String(parsed.status || '').trim().toLowerCase();

// Bezahlt-Logik
const is_paid = status === 'bezahlt';

// Optional: Rechnung aus vorherigem Node holen
const invoice = $('KI Ergebnis normalisieren').first().json.invoice || {};

// Ergebnis sauber zurückgeben
return [
  {
    json: {
      ...$json,

      status,
      is_paid,

      confidence: parsed.confidence ?? 0,
      matched_transaction_id: parsed.matched_transaction_id ?? null,
      matched_date: parsed.matched_date ?? null,
      matched_amount: parsed.matched_amount ?? null,
      reason: parsed.reason ?? '',

      todo_title: parsed.todo_title || '',
      todo_description: parsed.todo_description || '',
      telegram_message: parsed.telegram_message || '',

      invoice,

      parsed_result: parsed
    }
  }
];

